<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="600rpx" :closeable="true" :z-index="100" @close="close" @open="open">
		<view class="popup-content">
			<view style="width: 500rpx;">
				<u-parse :html="form.tip" v-if="form.tip" :selectable="true" :show-with-animation="true"></u-parse>
				<u-form :labelWidth="140" label-position="top">
					<!-- <u-form-item label="账号" v-if="form.account">
						<view style="line-height: 34rpx;word-break:break-all" @click="handelCopyText(form.account)">
							{{form.account}}
							<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item>
					<u-form-item label="姓名" v-if="form.true_name">
						<view style="line-height: 34rpx;word-break:break-all" @click="handelCopyText(form.true_name)">
							{{form.true_name}}<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30"
								color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item> -->
					
						<u-form-item label="付款金额">
							<text style="color: red;margin:0 10rpx;"> {{ form.total_price }} </text> 元  可用卡密<span style="color: red;margin:0 10rpx;"> {{ form.card_num }} </span>张
						</u-form-item>
					
					<!-- <template v-else>
						<u-form-item label="付款金额">
							<money-list :list="form.pay_list" />
						</u-form-item>
					</template> -->
					
						

					
						<u-form-item label="骏卡内容"   prop="card_data">
							<u-input v-model="form.card_data" height="220" :placeholder="placeholder" type="textarea" />
						</u-form-item>

						<u-form-item :border-bottom="false">
							<view class="btn bg-blue" style="width: 100%;" @click="$u.throttle(ok, 1000)">确认支付</view>
						</u-form-item>
					
				</u-form>
			</view>
		</view>
	</u-popup>

</template>

<script>
	import { mapGetters } from 'vuex'
	export default {
		components: {
	
		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			source: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				popupShow: false,
				  placeholder:'格式(每张占一行)：\n{卡号} {密码}\n\n 示例(卡号密码空格隔开)：\n1234567890123456 1234567890123456',
				form: {
					card_num:5,
						card_data: '',
				},
				
			
				
			}
		},
		computed: {
			...mapGetters(['sysconfig']),
			moneyType() {
				if (Reflect.has(this.form, 'pay_list')) return 1
				else return 0
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			},
			source: {
				handler(nv) {
					this.form = nv
				},
				deep: true,
			},
		},
		methods: {
			open() {},
			close() {
				this.$emit('update:show', false)
			},
			// 转账加款-确认支付
			async ok() {
				if (!this.form.card_data) {
					this.$util.msg('请输入卡密');
					return
				}

				const {
					status,
					url
				} = await this.$u.api.payStatus({
					order_sn: this.form.order_sn,
					trade_sn: this.form.trade_sn,
					pay_id: this.form.pay_id,
					card_data: this.form.card_data,
				})
				if (status == 1) {
					this.$util.msg('支付成功')
					this.$emit('pay-ok', {
						url
					})

				} else {
					this.$util.msg('订单未支付')
				}

			},
			// 图片预览
			handelGoodsImgClick(url) {
				uni.previewImage({
					urls: [url],
					current: 0
				})
			},
			// 复制文本
			handelCopyText(txt) {
				uni.setClipboardData({
					data: txt,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		&>.title {
			font-weight: bolder;
			font-size: 30rpx;
		}
	}
</style>