<template>
	<view class="page-box">
		<!-- <view class="back-img" @click="$util.back()"></view> -->

		<view class="open_substation" :style="{
				backgroundImage:'url('+$util.img(bg)+')',
			}">
			<view class="tips">
				<view class="title">
					成为分销商
					<image class="crown" :src="huangguan" mode="aspectFit"></image>
				</view>
				<view class="logo-text">
					自购省钱 拓客赚钱
				</view>
			</view>

			<view class="content">
				<view class="join-show">
					<view class="title"
						:style="{ '--right-qy-bg': 'url('+img_right+')','--left-qy-bg': 'url('+img_left+')',}">
						专属权益
					</view>
					<view class="gird-box">
						<view class="item" v-for="(item,index) in quanyiList" :key="index">
							<image class="img" :src="item.img" mode="aspectFit"></image>
							<view class="name">
								{{item.title}}
							</view>
						</view>
					</view>
				</view>
			</view>
			<view class="btn-box">
				<view class="submit-btn" v-if="!is_have_vip" @click="openmeal">
					立即开通
				</view>
				<view class="submit-btn" v-if="is_have_vip && !vip_url" style="background: #ccc;color: #fff;">
					已开通
				</view>
				<view class="submit-btn" v-if="is_have_vip && vip_url" @click="$util.on(vip_url)">
					管理站点
				</view>
			</view>

			<u-popup v-model="show" mode="center" width="686" :border-radius="16" z-index="9">

				<view class="modal-box">
					<u-icon name="close" class="close" @click="show= false"></u-icon>
					<view class="title">
						{{' 开通分站 '}}
					</view>
					<view class="form-item">
						<view class="label">
							{{' 站点名称 '}}
						</view>
						<view class="item-value">
							<input type="text" v-model="site_name" placeholder-style="color:#d8dbe3;" class="input long"
								placeholder="请输入站点名称">
						</view>
					</view>

					<view class="form-item">
						<view class="label">
							{{' 站点版本 '}}
						</view>
						<view class="item-value">

							<picker v-if="mealList.length>0" class="picker-box input" @change="changeMeal"
								@cancel="mealicon=true" @click="mealicon =false" :value="0" :range="mealList"
								range-key="_vip_type">
								<view class="xinmeng-select-box">
									<view class="xinmeng-select">
										<view class="text">{{mealList[meal]._vip_type}}</view>
										<u-icon :name="mealicon ? 'arrow-down-fill':'arrow-up-fill'" color="#b9b9b9"
											size="28"></u-icon>
									</view>
								</view>
							</picker>
						</view>
					</view>
					<view class="form-item">
						<view class="label">
							{{' 站点域名 '}}
						</view>
						<view class="item-value">
							<input type="text" class="input " v-model="qz" placeholder-style="color:#d8dbe3;"
								placeholder="请输入域名前缀">
							<picker class="picker-box input short" v-if="domainList.length>0" @change="changeDomain"
								@cancel="domainicon=true" @click="domainicon =false" :value="0" :range="domainList"
								range-key="url">

								<view class="xinmeng-select-box">
									<view class="xinmeng-select">
										<text class="text">{{domainList[domain].url}}</text>
										<u-icon :name="domainicon ? 'arrow-down-fill':'arrow-up-fill'" color="#b9b9b9"
											size="28"></u-icon>
									</view>
								</view>
							</picker>
						</view>
					</view>

					<view class="submit-btn" @click="clickpay">
						<text class="money">{{price}}</text>
						确认支付
					</view>
				</view>


			</u-popup>

		</view>
		<pay-way-popup v-model="showPayWayPopup" :create-order="createOrder" :payMoney="price" @success="paySuccess" />
	</view>
</template>

<script>
	import PayWayPopup from '@/components/pay-way/popupV2'
	import _ from 'lodash'

	export default {
		components: {
			'pay-way-popup': PayWayPopup
		},
		data() {
			return {
				huangguan: '',
				bg: '/statics/uni/img/vipapply/img_bg.png',
				quanyiList: [],
				img_left: '',
				img_right: '',
				mealList: [], //套餐列表
				domainList: [], //域名列表

				show: false,

				domainicon: true,
				mealicon: true,
				domain: 0,
				meal: 0,
				price: '0.00',
				qz: '', //前缀
				hz: '', //后缀
				trade_password: '',
				site_name: '',
				is_have_vip: false,
				vip_url: '',

				// 选择支付方式弹窗
				showPayWayPopup: false,
			};
		},
		computed: {
			formData() {
				return {
					meal_id: this.mealList[this.meal]?.id,
					qz: this.qz,
					hz: this.domainList[this.domain]?.url,
					site_name: this.site_name,
					trade_password: this.trade_password,
					money: this.price,
				}
			}
		},
		onLoad(e) {
			this.loadData()
		},
		methods: {
			openmeal() {
				if (this.mealList.length == 0) {
					this.$util.msg('无套餐可开通')
				} else {
					this.show = !this.show
				}
			},
			clickpay: _.throttle(function() {
				if (!this.site_name || this.site_name == '') {
					this.$util.msg('请输入站点名称')
					return;
				}

				if (!this.qz || this.qz == '') {
					this.$util.msg('请输入域名前缀')
					return;
				}

				if (this.qz == '') {
					this.$util.msg('请输入域名前缀');
					return;
				}
				this.showPayWayPopup = true
			}, 1000, {
				trailing: false
			}),
			async createOrder(paywayForm) {
				const res = await this.$u.api.vipapply({
					...this.formData,
					...paywayForm
				})
				return res
			},
			changeMeal(e) {
				this.mealicon = true
				this.meal = e.detail.value
				this.price = this.mealList[this.meal].price
			},
			changeDomain(e) {
				this.domainicon = true
				this.domain = e.detail.value
				this.loadData(idx)
			},
			// 页面数据
			async loadData(idx) {
				await this.$u.api.vipapplyConfig({
						meal_type: idx
					})
					.then(res => {
						this.quanyiList = res.quanyiList
						this.bg = res.bg
						this.huangguan = res.huangguan
						this.img_right = res.img_right
						this.img_left = res.img_left
						this.mealList = res.mealList
						this.domainList = res.domainList
						this.is_have_vip = res.is_have_vip
						this.vip_url = res.vip_url
						this.need_trade_password = res.need_trade_password

						if (this.mealList.length > 0) {
							this.price = this.mealList[this.meal].price
						}
					}).catch(res => {})

			},
			// 支付成功回调
			paySuccess(e) {
				this.$util.msg('开通成功')
				// #ifdef H5
				window.open(e.url, '_blank')
				// #endif
				this.show = false
				this.loadData()
			}
		}
	};
</script>



