<template>
	<view class="comp-box">
		<view class="now-price" :style="{color:nowPriceColor}" v-if="showNowPrice">
			<view class="symbol">{{moneySymbol}}</view>
			<view class="money">
				<text class="int-part">{{nowPriceArr[0]}}</text>
				<template v-if="nowPriceArr[1]">
					<text class="dian">.</text>
					<text class="decimal-part">{{nowPriceArr[1]}}</text>
				</template>
			</view>
		</view>
		<view class="old-price" :style="{color:oldPriceColor}" v-if="showOldPrice">
			<view class="symbol">{{moneySymbol}}</view>
			<view class="money">{{oldPrice}}</view>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			showNowPrice: {
				type: Boolean,
				default: true,
			},
			nowPrice: {
				type: [Number, String],
				default: 0
			},
			oldPrice: {
				type: [Number, String],
				default: 0
			},
			showOldPrice: {
				type: Boolean,
				default: true
			},
			moneySymbol: {
				type: String,
				default: '￥'
			},
			nowPriceColor: {
				type: String,
				default: '#ed171f'
			},
			oldPriceColor: {
				type: String,
				default: '#rgb(153, 153, 153)'
			},
		},
		computed: {
			nowPriceArr() {
				let re = []
				let price_str = this.nowPrice.toString()
				if (price_str.indexOf('.') == -1) {
					re.push(price_str)
				} else {
					re = price_str.split('.')
				}

				return re
			}
		},
		methods: {
			name() {

			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.comp-box {
		width: 100%;
		display: flex;
		flex-wrap: nowrap;
		align-items: center;
		justify-content: space-between;
		gap: 10rpx;

		.now-price {
			display: flex;
			align-items: baseline;
			color: #ed171f;
			font-size: 32rpx;

			.symbol {
				font-size: 28rpx;
			}

			.money {
				.int-part {
					font-size: 38rpx;
				}

				.decimal-part {
					font-size: 28rpx;
				}
			}
		}

		.old-price {
			display: flex;
			align-items: center;
			color: rgb(153, 153, 153);
			text-decoration: line-through;
			font-size: 24rpx;
		}
	}
</style>